import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b) | set(a))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        status = ""
        if bv and av:
            status = f"Aligned to highest ({bv} -> {av})"
        elif not bv:
            status = "Added"
        else:
            status = "Removed"
        changes.append((k[0], k[2], k[1], bv or '(none)', av or '(none)', status))
    else:
        unchanged.append((k[0], k[2], k[1], av))

if changes:
    print('=== CHANGES ===')
    for c in changes:
        print(f'  {c[0]:15} | {c[2]:8} | {c[1]:50} | {c[3]:12} -> {c[4]:12} | {c[5]}')
else:
    print('No unexpected version changes.')

print(f'\n=== UNCHANGED ({len(unchanged)} packages) ===')
for u in unchanged:
    print(f'  {u[0]:15} | {u[2]:8} | {u[1]:50} | {u[3]}')
